import { z } from 'zod';
import { Document } from '@loopstack/common';

// ── Per-ticket evaluation (generated by LLM for each ticket) ──

export const TicketEvaluationSchema = z
  .object({
    factualAccuracy: z.number().min(0).max(100).describe('Percentage of required facts present in the response.'),
    correctResolution: z.boolean().describe('Whether the agent arrived at the correct resolution.'),
    noPitfalls: z.boolean().describe('Whether the agent avoided all listed pitfalls.'),
    pitfallsHit: z.array(z.string()).describe('List of pitfalls the agent fell into, if any.'),
    notes: z.string().describe('Brief evaluator notes on this ticket.'),
  })
  .strict();

export type TicketEvaluationType = z.infer<typeof TicketEvaluationSchema>;

@Document({
  schema: TicketEvaluationSchema,
})
export class TicketEvaluationDocument {
  factualAccuracy: number;
  correctResolution: boolean;
  noPitfalls: boolean;
  pitfallsHit: string[];
  notes: string;
}

// ── Summary (generated by LLM after all tickets are evaluated) ──

export const EvaluationSummarySchema = z
  .object({
    summary: z
      .string()
      .describe(
        'Markdown summary covering: overall assessment, top strengths (2-3 bullets), key weaknesses (2-3 bullets), and specific recommendations.',
      ),
  })
  .strict();

export type EvaluationSummaryType = z.infer<typeof EvaluationSummarySchema>;

@Document({
  schema: EvaluationSummarySchema,
})
export class EvaluationSummaryDocument {
  summary: string;
}

// ── Combined result returned by the workflow ──

export interface EvaluationResult {
  ticketEvaluations: (TicketEvaluationType & { ticketId: string })[];
  kpis: {
    avgFactualAccuracy: number;
    correctResolutionRate: number;
    pitfallAvoidanceRate: number;
    overallScore: number;
  };
  summary: string;
}
